import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Keyboard-Navigable Dropdown', () => {
  it('trigger has aria-haspopup and aria-expanded', () => {
    render(<App />);
    const trigger = screen.getByTestId('dropdown-trigger');
    expect(trigger).toHaveAttribute('aria-haspopup', 'true');
    expect(trigger).toHaveAttribute('aria-expanded', 'false');
  });

  it('opens menu on trigger click', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('dropdown-trigger'));
    expect(screen.getByTestId('dropdown-menu')).toBeInTheDocument();
    expect(screen.getByTestId('dropdown-trigger')).toHaveAttribute('aria-expanded', 'true');
  });

  it('menu has role=menu and items have role=menuitem', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('dropdown-trigger'));
    expect(screen.getByTestId('dropdown-menu')).toHaveAttribute('role', 'menu');
    expect(screen.getByTestId('menu-item-0')).toHaveAttribute('role', 'menuitem');
  });

  it('arrow down moves focus to next item', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('dropdown-trigger'));
    const menu = screen.getByTestId('dropdown-menu');
    fireEvent.keyDown(menu, { key: 'ArrowDown' });
    expect(document.activeElement).toBe(screen.getByTestId('menu-item-1'));
  });

  it('escape closes menu', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('dropdown-trigger'));
    const menu = screen.getByTestId('dropdown-menu');
    fireEvent.keyDown(menu, { key: 'Escape' });
    expect(screen.queryByTestId('dropdown-menu')).not.toBeInTheDocument();
  });

  it('enter selects focused item', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('dropdown-trigger'));
    const item = screen.getByTestId('menu-item-0');
    item.focus();
    fireEvent.keyDown(item, { key: 'Enter' });
    expect(screen.getByTestId('output')).toHaveTextContent('Edit');
  });

  it('clicking an item selects it and closes menu', () => {
    render(<App />);
    fireEvent.click(screen.getByTestId('dropdown-trigger'));
    fireEvent.click(screen.getByTestId('menu-item-2'));
    expect(screen.getByTestId('output')).toHaveTextContent('Archive');
    expect(screen.queryByTestId('dropdown-menu')).not.toBeInTheDocument();
  });
});

