import React, { useState, useRef, useEffect, useCallback } from 'react';
import './styles.css';

interface MenuItem {
  label: string;
  action: string;
}

interface DropdownProps {
  items: MenuItem[];
}

export const Dropdown: React.FC<DropdownProps> = ({ items }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [output, setOutput] = useState('Select an action');
  const [focusedIndex, setFocusedIndex] = useState(0);
  const triggerRef = useRef<HTMLButtonElement>(null);
  const itemRefs = useRef<(HTMLDivElement | null)[]>([]);
  const menuRef = useRef<HTMLDivElement>(null);

  const handleSelect = useCallback((item: MenuItem) => {
    setOutput(`Selected: ${item.label}`);
    setIsOpen(false);
    triggerRef.current?.focus();
  }, []);

  // Focus first item when menu opens
  useEffect(() => {
    if (isOpen) {
      setFocusedIndex(0);
      setTimeout(() => itemRefs.current[0]?.focus(), 0);
    }
  }, [isOpen]);

  // Click outside to close
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e: MouseEvent) => {
      if (!menuRef.current?.contains(e.target as Node) && !triggerRef.current?.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [isOpen]);

  const handleMenuKeyDown = (e: React.KeyboardEvent) => {
    switch (e.key) {
      case 'ArrowDown': {
        e.preventDefault();
        const next = (focusedIndex + 1) % items.length;
        setFocusedIndex(next);
        itemRefs.current[next]?.focus();
        break;
      }
      case 'ArrowUp': {
        e.preventDefault();
        const prev = (focusedIndex - 1 + items.length) % items.length;
        setFocusedIndex(prev);
        itemRefs.current[prev]?.focus();
        break;
      }
      case 'Home':
        e.preventDefault();
        setFocusedIndex(0);
        itemRefs.current[0]?.focus();
        break;
      case 'End':
        e.preventDefault();
        setFocusedIndex(items.length - 1);
        itemRefs.current[items.length - 1]?.focus();
        break;
      case 'Escape':
        setIsOpen(false);
        triggerRef.current?.focus();
        break;
      case 'Enter':
      case ' ':
        e.preventDefault();
        handleSelect(items[focusedIndex]);
        break;
    }
  };

  return (
    <div className="dropdown">
      <button
        ref={triggerRef}
        data-testid="dropdown-trigger"
        className="dropdown__trigger"
        aria-haspopup="true"
        aria-expanded={isOpen}
        onClick={() => setIsOpen(!isOpen)}
      >
        Actions ▾
      </button>

      {isOpen && (
        <div
          ref={menuRef}
          data-testid="dropdown-menu"
          className="dropdown__menu"
          role="menu"
          onKeyDown={handleMenuKeyDown}
        >
          {items.map((item, i) => (
            <div
              key={item.action}
              ref={el => { itemRefs.current[i] = el; }}
              data-testid={`menu-item-${i}`}
              className="dropdown__item"
              role="menuitem"
              tabIndex={i === focusedIndex ? 0 : -1}
              onClick={() => handleSelect(item)}
              onKeyDown={e => {
                if (e.key === 'Enter' || e.key === ' ') {
                  e.preventDefault();
                  handleSelect(item);
                }
              }}
            >
              {item.label}
            </div>
          ))}
        </div>
      )}

      <p data-testid="output" className="dropdown__output">{output}</p>
    </div>
  );
};
